using Forge.Core.Entities;
using Forge.Core.Enums;
using Forge.Data.Context;

using Serilog;

namespace Forge.Api.Data.TrainingContent;

public class MrpTraining : TrainingContentBase
{
    public MrpTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "MRP Overview",
            Slug = "mrp-overview",
            Summary = "What Material Requirements Planning is, how MRP runs net demand against supply, planned orders, exceptions, the master schedule, and demand forecasts.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/mrp"]""",
            Tags = """["mrp","planning"]""",
            ContentJson = """{"body":"## MRP Overview\n\nThe MRP (Material Requirements Planning) module answers a single question for every part you make or buy: *what do I need, how much, and when?* It does this by collecting all the **demand** for each part (sales orders, master schedule entries, forecasts, manual demand, and dependent demand from BOMs), netting it against all the **supply** (on-hand inventory, open purchase orders, planned orders, production runs, and in-transit stock), and then generating **planned orders** to cover whatever shortfall remains — timed by each part's lead time.\n\n### The Core Idea: Demand/Supply Netting\n\nFor each part, MRP walks forward through time. It starts with projected on-hand inventory, subtracts gross requirements (demand) as they come due, adds scheduled receipts (supply already on order), and whenever the projected balance would go negative it creates a **planned order release** sized and dated to bring the balance back to zero. The result is a time-phased plan: a set of planned orders, each with a quantity, a start date, and a due date.\n\n### Running MRP\n\nFrom the MRP **Dashboard** you launch a run two ways:\n- **Run MRP** — commits the plan. Planned orders and exceptions are saved and become actionable.\n- **Simulate** — runs the exact same calculation but flags the run as a simulation so you can preview the impact of a change without touching the live plan.\n\nWhen you launch a run, a parameter dialog asks for the **run type** and **planning horizon** (how many days into the future to plan). The three run types are:\n- **Full** — re-plans every part from scratch. The safe default.\n- **Net Change** — re-plans only parts whose demand or supply changed since the last run. Faster, for incremental updates.\n- **Simulation** — a what-if run that never alters the live plan.\n\nEach run records counts you can see at a glance: total demands, total supplies, planned orders generated, and exceptions raised.\n\n### Reading a Run in Detail (Drill-Down)\n\nThe **Run History** tab lists every run; click any run row to open its **Run Detail** dialog and see exactly what the run did. The top of the dialog repeats the run's summary (type, status, horizon, demand/supply counts, planned-order and exception counts, and any error message). Below that, the dialog splits into two panels:\n\n- **Parts touched** (left) — every part the run generated a planned order for, with that part's order count and total planned quantity. Click a part to drill in.\n- **Time-phased buckets** (right) — once you pick a part, you see its period-by-period plan as a table. Each bucket (row) shows the **gross requirements** (demand falling in that period), **scheduled receipts** (supply already on order), **PO receipts**, the **projected on-hand** balance (highlighted when it goes negative), the **net requirements** (the shortfall MRP must cover), and the **planned-order releases** it created. This is the literal demand/supply netting walk, period by period, for that one part.\n- **Pegging** (below the buckets) — the traceability trail that answers *why* a supply was suggested. Each pegging row links a demand (its source, quantity, and required date) to the supply (source, quantity, date) that MRP allocated to cover it. Pegging is how you trace a planned order back to the sales order or master-schedule line that drove it.\n\nUse Run Detail to verify a run before you act on its orders, to explain why a planned order exists, or to investigate an unexpected shortage on a single part.\n\n### Planned Orders\n\nEvery planned order is either a **Purchase** order suggestion (for bought parts) or a **Manufacture** order suggestion (for made parts). A planned order moves through a short lifecycle:\n1. **Planned** — freshly generated by MRP. The next run can change or delete it.\n2. **Firmed** — you have locked it. A firmed order is protected — future MRP runs will not move or delete it, even if demand shifts. Use this when you have committed to the timing.\n3. **Released** — you have converted it into a real document. Releasing a Purchase planned order creates a Purchase Order; releasing a Manufacture planned order creates a Job. The created entity's type and ID are recorded on the order.\n4. **Cancelled** — no longer needed.\n\nThe **Planned Orders** tab has a status filter at the top so you can narrow the list to just Planned, Firmed, Released, or Cancelled orders (or All).\n\n### Exceptions\n\nMRP does not silently fix everything — when the plan implies an action you should review, it raises an **exception** with a message and a suggested action. The exception types are: **Expedite** (pull a supply order in), **Defer** (push a supply order out), **Cancel** (a supply order is no longer needed), **Past Due** (a required date is already in the past), **Short Supply** (not enough supply to cover demand), **Over Supply** (more on order than needed), and **Lead Time Violation** (the lead time can't be met). You resolve each exception once you've acted on it, which clears it from the unresolved list. The **Exceptions** tab opens filtered to **Unresolved only** by default; switch the filter to **All** to also see exceptions you've already resolved.\n\n### Master Schedule (MPS)\n\nThe **Master Production Schedule** is a manually authored statement of what you intend to build, independent of confirmed sales orders. Each master schedule has a name, a period (start/end), and lines (part + quantity + due date). A schedule is created in **Draft**, then **Activated** so MRP treats its lines as demand; it later becomes **Completed** or **Cancelled**. You can re-open any schedule with the **edit** action to change its name, period, or lines — add a line (part + quantity + due date + optional notes), edit an existing line, or remove one — and save. For active or completed schedules you can open an **MPS vs Actual** view that compares planned quantities to what was actually produced, with **Variance** and **Variance %** columns (per part and a total row) so you can see where you over- or under-built.\n\n### Demand Forecasts\n\nWhen you don't have firm orders far enough out, you generate a **Demand Forecast** for a part from its sales history. You pick a forecast **method** — Moving Average, Weighted Moving Average, or Exponential Smoothing — along with how many historical periods to learn from and how many periods to project. A forecast is created in **Draft**; you **Approve** it (making it **Approved**), and it can then be **Applied** to a master schedule so it feeds MRP as demand. Forecasts expire over time. You can override individual forecast buckets, and the override count is tracked.\n\n### How MRP Connects to the Rest of QB Engineer\n\n**Sales Orders** feed MRP as the most direct source of demand. **BOMs** drive dependent demand — building a parent part explodes into requirements for its components. **Purchase Orders** and **Jobs** are the downstream outputs: releasing a planned order creates one of them. **Inventory** supplies the on-hand starting balance for every part's netting. **Lead times** on each part determine how far before the due date a planned order must start.\n\n### When to Use MRP\n\n- After taking new orders, to see what you need to buy or build and by when\n- Before a planning cycle, to turn the master schedule and forecasts into actionable orders\n- To catch timing problems early via exceptions (past-due, short-supply, expedite)\n- To simulate the impact of a demand change before committing to it\n- To convert the plan into real Purchase Orders and Jobs once you firm it","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "MRP — Guided Tour",
            Slug = "mrp-walkthrough",
            Summary = "A guided tour of the MRP workspace: the dashboard KPIs, running and simulating MRP, planned orders, exceptions, run history, the master schedule, and forecasts.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/mrp"]""",
            Tags = """["mrp","planning","walkthrough"]""",
            ContentJson = """{"appRoute":"/mrp","startButtonLabel":"Tour MRP","steps":[{"element":".tab-bar","popover":{"title":"MRP Tabs","description":"The MRP workspace is organized into six tabs: Dashboard (KPIs and unresolved exceptions), Planned Orders, Exceptions, Run History, Master Schedule, and Forecasts. The active tab is stored in the URL, so you can bookmark or share any view.","side":"bottom"}},{"element":".mrp__kpis","popover":{"title":"Dashboard KPIs","description":"At-a-glance health of your plan: the latest run number, the count of Planned orders, the count of Firmed orders, and the count of unresolved exceptions. The exception chip turns red when there is anything to act on and green when you are clear.","side":"bottom"}},{"element":"[data-testid='mrp-run-btn']","popover":{"title":"Run MRP","description":"Launches a committed MRP run. A dialog asks for the run type (Full re-plans everything, Net Change re-plans only what moved) and the planning horizon in days. The run nets demand against supply for every part and saves the resulting planned orders and exceptions.","side":"bottom"}},{"element":"[data-testid='mrp-simulate-btn']","popover":{"title":"Simulate","description":"Runs the identical calculation but marks it as a simulation so it never alters your live plan. Use this to preview the impact of a demand or supply change before committing with Run MRP.","side":"bottom"}},{"element":".mrp__kpis","popover":{"title":"Unresolved Exceptions","description":"The unresolved-exceptions KPI here counts issues the latest run raised — Expedite, Defer, Cancel, Past Due, Short Supply, Over Supply, and Lead Time Violation. When the count is above zero, the dashboard lists those exceptions below with the affected part, message, and suggested action, and you click the check icon on a row to mark it resolved once you've acted on it.","side":"bottom"}},{"element":".tab-bar","popover":{"title":"Planned Orders & Releasing","description":"Open the Planned Orders tab to see every suggestion MRP generated — Purchase or Manufacture, with quantity, start date, and due date. A status filter at the top narrows the list to Planned, Firmed, Released, or Cancelled. Use the lock icon to Firm an order (protecting it from future runs) and the send icon to Release it, which creates a real Purchase Order or Job from the suggestion.","side":"bottom"}},{"element":".tab-bar","popover":{"title":"Run History & Run Detail","description":"The Run History tab lists every run. Click any run row to open its Run Detail dialog: the summary up top, then a 'parts touched' list — click a part to see its time-phased buckets (gross requirements, scheduled and PO receipts, projected on-hand, net requirements, planned-order releases) and the pegging trail that traces each supply back to the demand that drove it. Use it to verify a run or explain why a planned order exists.","side":"bottom"}},{"element":".tab-bar","popover":{"title":"Master Schedule & Forecasts","description":"The Master Schedule tab lets you author, edit, and activate an MPS (your build plan, independent of sales orders). The pencil icon re-opens a schedule to change its name, period, or lines; once it is Active or Completed, the bar-chart icon opens MPS vs Actual with Variance and Variance % columns. The Forecasts tab generates demand forecasts from sales history using Moving Average, Weighted Moving Average, or Exponential Smoothing, then approves them so MRP can plan against them.","side":"bottom"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "MRP Field Reference",
            Slug = "mrp-field-reference",
            Summary = "Complete reference for MRP run types and statuses, planned order fields and lifecycle, exception types, master schedule and forecast fields, and every action.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/mrp"]""",
            Tags = """["mrp","planning","reference"]""",
            ContentJson = """{"title":"MRP Field Reference","groups":[{"heading":"Run Types","items":[{"label":"Full","value":"Re-plans every part from scratch. The safe default — use when demand or supply has changed broadly or you want a clean replan."},{"label":"Net Change","value":"Re-plans only parts whose demand or supply changed since the last run. Faster than Full; use for incremental updates."},{"label":"Simulation","value":"A what-if run flagged as a simulation. Runs the same calculation but never alters the live plan. Launched via the Simulate button."}]},{"heading":"Run Statuses","items":[{"label":"Queued (muted chip)","value":"The run has been requested and is waiting to start."},{"label":"Running (info chip)","value":"The run is actively netting demand against supply."},{"label":"Completed (success chip)","value":"The run finished. Planned orders and exceptions are saved (unless it was a simulation)."},{"label":"Failed (error chip)","value":"The run errored. An error message is recorded on the run record."}]},{"heading":"Run Record Fields","items":[{"label":"Run Number","value":"Auto-generated unique identifier for the run."},{"label":"Type","value":"Full, Net Change, or Simulation."},{"label":"Planning Horizon Days","value":"How many days into the future the run planned. Set in the execute dialog."},{"label":"Total Demand Count","value":"Number of demand records considered across all parts."},{"label":"Total Supply Count","value":"Number of supply records considered across all parts."},{"label":"Planned Order Count","value":"Number of planned orders the run generated."},{"label":"Exception Count","value":"Number of exceptions the run raised."},{"label":"Started / Completed","value":"Timestamps for the run, formatted as date/time. Click a run row in Run History to open its detail."}]},{"heading":"Run Detail (Drill-Down)","items":[{"label":"How to open","value":"Run History tab → click any run row. Run-detail rows are clickable; the dialog opens for that run."},{"label":"Summary header","value":"Repeats the run's Type, Status, planning horizon, demand and supply counts, planned-order count, exception count, and any error message."},{"label":"Parts touched (left panel)","value":"Every part the run created planned orders for, with that part's order count and total planned quantity. Click a part to drill in."},{"label":"Time-phased buckets (right panel)","value":"Per-period plan for the selected part. Columns: Bucket Start, Gross requirements, Scheduled receipts, PO receipts, projected On-hand (highlighted when negative), Net requirements, and planned-order Releases."},{"label":"Pegging","value":"Traceability trail under the buckets: each row links a demand (source, qty, required date) to the supply (source, qty, date) MRP allocated to cover it. Shows which sales order / master-schedule line drove a planned order."}]},{"heading":"Per-Tab Filter Controls","items":[{"label":"Planned Orders — Status filter","value":"Dropdown at the top of the Planned Orders tab: All, Planned, Firmed, Released, or Cancelled. Narrows the list to one status."},{"label":"Exceptions — Unresolved/All filter","value":"Dropdown at the top of the Exceptions tab: Unresolved only (the default — matches the dashboard's unresolved count) or All (also shows already-resolved exceptions)."},{"label":"Column filters (all data tables)","value":"Each tab's data table also offers per-column filter/sort (e.g., filter Planned Orders by Order Type, runs by Type, schedules/forecasts by Status) via the column header."}]},{"heading":"Planned Order Fields","items":[{"label":"Part Number / Description","value":"The part the planned order is for."},{"label":"Order Type","value":"Purchase (suggests buying — releases to a Purchase Order) or Manufacture (suggests building — releases to a Job)."},{"label":"Status","value":"Planned, Firmed, Released, or Cancelled."},{"label":"Quantity","value":"How many units the order suggests, sized to cover the net requirement."},{"label":"Start Date","value":"When the order must start to meet the due date, offset by lead time."},{"label":"Due Date","value":"When the order's quantity is required to be available."},{"label":"Firmed","value":"Lock indicator. A firmed order is protected from future MRP runs (lock icon = firmed, open lock = not firmed)."}]},{"heading":"Planned Order Lifecycle","items":[{"label":"Planned (info chip)","value":"Freshly generated by MRP. A future run can change or delete it."},{"label":"Firmed (warning chip)","value":"You locked it. Future runs will not move or delete it. Set via the lock icon on a Planned order."},{"label":"Released (success chip)","value":"Converted into a real document — a Purchase Order or a Job. The created entity type and ID are recorded. Set via the send icon."},{"label":"Cancelled (muted chip)","value":"No longer needed; removed from the active plan."}]},{"heading":"Exception Types","items":[{"label":"Expedite","value":"A supply order should be pulled in (made to arrive sooner) to meet demand."},{"label":"Defer","value":"A supply order can be pushed out (it's earlier than needed)."},{"label":"Cancel","value":"A supply order is no longer needed and should be cancelled."},{"label":"Past Due","value":"A required date is already in the past."},{"label":"Short Supply","value":"Not enough supply to cover the demand for this part."},{"label":"Over Supply","value":"More on order than is needed for this part."},{"label":"Lead Time Violation","value":"The part's lead time cannot be met for the required date."}]},{"heading":"Master Schedule (MPS) Fields","items":[{"label":"Name / Description","value":"Identifies the master schedule."},{"label":"Status","value":"Draft (editable, not yet planning), Active (lines treated as demand by MRP), Completed, or Cancelled."},{"label":"Period Start / End","value":"The window the schedule covers."},{"label":"Lines","value":"Each line is a part + quantity + due date (+ optional notes). Line count is shown in the list."},{"label":"MPS vs Actual","value":"For Active or Completed schedules, compares planned quantity to actual produced quantity, with variance and variance percent. Opened via the bar-chart icon."}]},{"heading":"Demand Forecast Fields","items":[{"label":"Name","value":"Identifies the forecast."},{"label":"Part","value":"The part being forecast."},{"label":"Method","value":"Moving Average, Weighted Moving Average, or Exponential Smoothing."},{"label":"Status","value":"Draft, Approved, Applied (fed to a master schedule), or Expired."},{"label":"Historical Periods","value":"How many past periods the method learns from."},{"label":"Forecast Periods","value":"How many future periods are projected."},{"label":"Smoothing Factor","value":"Used by Exponential Smoothing; weights recent data vs older data."},{"label":"Override Count","value":"How many individual forecast buckets you manually overrode."}]},{"heading":"Buttons and Actions","items":[{"label":"Run MRP (dashboard / run history)","value":"Opens the execute dialog, then commits a run. data-testid: mrp-run-btn"},{"label":"Simulate (dashboard / run history)","value":"Opens the execute dialog in simulation mode — runs without altering the live plan. data-testid: mrp-simulate-btn"},{"label":"Firm (planned orders)","value":"Lock icon. Firms a Planned order so future runs won't change it."},{"label":"Release (planned orders)","value":"Send icon. Converts a Planned or Firmed order into a Purchase Order (Purchase) or Job (Manufacture). Available for Planned and Firmed orders."},{"label":"Resolve (exceptions)","value":"Check/done icon. Marks an unresolved exception as resolved after you've acted on it."},{"label":"Open Run Detail","value":"Click a run row in Run History to open the drill-down dialog (parts touched, time-phased buckets, pegging)."},{"label":"New Master Schedule","value":"Opens the create dialog for a master schedule. data-testid: mrp-schedule-new-btn"},{"label":"Edit Schedule","value":"Pencil icon on a schedule row. Re-opens the schedule to change its name, period, or lines (add/edit/remove lines), then save."},{"label":"Activate Schedule","value":"Play icon. Moves a Draft master schedule to Active so MRP plans against its lines."},{"label":"MPS vs Actual","value":"Bar-chart icon. Opens the planned-vs-actual variance view for Active/Completed schedules."},{"label":"New Forecast","value":"Opens the generate-forecast dialog. data-testid: mrp-forecast-new-btn"},{"label":"Approve Forecast","value":"Check icon. Moves a Draft forecast to Approved so it can be applied."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "MRP Knowledge Check",
            Slug = "mrp-quiz",
            Summary = "Test your knowledge of MRP: demand/supply netting, run types, planned order lifecycle, exceptions, the master schedule, and demand forecasts.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/mrp"]""",
            Tags = """["mrp","planning","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"mr1","text":"What does an MRP run fundamentally do for each part?","options":[{"id":"a","text":"It deletes all open purchase orders and rebuilds them"},{"id":"b","text":"It nets all demand against all supply and generates planned orders to cover any shortfall, timed by lead time","isCorrect":true},{"id":"c","text":"It only counts current on-hand inventory and reports the total"},{"id":"d","text":"It automatically ships finished goods to customers"}],"explanation":"MRP collects demand (sales orders, master schedule, forecasts, dependent demand) and supply (on-hand, POs, planned orders, production runs, in-transit), nets them part by part over time, and creates planned orders sized and dated to cover whatever the projected balance can't meet."},{"id":"mr2","text":"You want to preview the effect of a demand change without touching your live plan. What do you use?","options":[{"id":"a","text":"Run MRP with run type Full"},{"id":"b","text":"The Simulate button, which runs the same calculation but flags it as a simulation and never alters the live plan","isCorrect":true},{"id":"c","text":"Net Change run type, which is read-only"},{"id":"d","text":"You must export the plan to a spreadsheet first"}],"explanation":"Simulate runs the identical netting calculation but marks the run as a simulation, so planned orders and the live plan are untouched. It's the what-if path. Run MRP (Full or Net Change) commits the result."},{"id":"mr3","text":"What is the difference between a Full run and a Net Change run?","options":[{"id":"a","text":"Full plans only purchased parts; Net Change plans only manufactured parts"},{"id":"b","text":"Full re-plans every part from scratch; Net Change re-plans only parts whose demand or supply changed since the last run","isCorrect":true},{"id":"c","text":"Full is a simulation; Net Change commits"},{"id":"d","text":"There is no difference — they are aliases"}],"explanation":"Full re-plans all parts (the safe default). Net Change is the faster incremental option that only re-plans parts that actually changed since the previous run."},{"id":"mr4","text":"You firm a planned order. What happens on the next MRP run?","options":[{"id":"a","text":"The firmed order is deleted and regenerated"},{"id":"b","text":"The firmed order is protected — future runs will not move or delete it","isCorrect":true},{"id":"c","text":"The firmed order is automatically released to a Purchase Order"},{"id":"d","text":"Firming has no effect on MRP runs"}],"explanation":"Firming locks a planned order. It's the way you tell MRP 'I've committed to this timing' so subsequent runs won't shift or remove it even if demand changes."},{"id":"mr5","text":"What does releasing a planned order do, and what gets created?","options":[{"id":"a","text":"It always creates an Invoice"},{"id":"b","text":"It converts the suggestion into a real document — a Purchase Order for a Purchase order, or a Job for a Manufacture order","isCorrect":true},{"id":"c","text":"It only changes the order's status with no downstream record"},{"id":"d","text":"It creates a Shipment"}],"explanation":"Releasing turns the planned-order suggestion into an actual document: Purchase-type planned orders create a Purchase Order, Manufacture-type planned orders create a Job. The created entity's type and ID are recorded on the order."},{"id":"mr6","text":"MRP raises a 'Short Supply' exception on a part. What does it mean?","options":[{"id":"a","text":"There is more on order than is needed"},{"id":"b","text":"There is not enough supply to cover the demand for that part","isCorrect":true},{"id":"c","text":"A supply order should be deferred to a later date"},{"id":"d","text":"The part's lead time was met successfully"}],"explanation":"Short Supply means the netting found insufficient supply to meet demand. (Over Supply is the opposite; Defer means push a supply out; Lead Time Violation means the lead time can't be met.) You act on the exception, then mark it resolved."},{"id":"mr7","text":"What is the Master Production Schedule (MPS), and how does it affect MRP?","options":[{"id":"a","text":"A read-only report of completed jobs"},{"id":"b","text":"A manually authored build plan (part + quantity + due date lines) that, once Activated, is treated as demand by MRP","isCorrect":true},{"id":"c","text":"The list of all purchase orders awaiting receipt"},{"id":"d","text":"A backup of the last MRP run"}],"explanation":"The MPS is your intended build plan, independent of confirmed sales orders. It's created in Draft, then Activated so MRP treats its lines as demand. You can later compare MPS vs Actual to see planned-vs-produced variance."},{"id":"mr8","text":"You generate a demand forecast for a part. Which methods are available and what is the status flow?","options":[{"id":"a","text":"Only Linear Regression; status goes Open then Closed"},{"id":"b","text":"Moving Average, Weighted Moving Average, or Exponential Smoothing; created Draft, then Approved, then optionally Applied to a master schedule (and forecasts Expire)","isCorrect":true},{"id":"c","text":"Any method you type in; there is no status"},{"id":"d","text":"Forecasts are generated automatically and cannot be approved"}],"explanation":"Forecasts use Moving Average, Weighted Moving Average, or Exponential Smoothing over a chosen number of historical periods. A forecast starts in Draft, is Approved, and can be Applied to a master schedule so MRP plans against it. Forecasts expire over time and individual buckets can be overridden."},{"id":"mr9","text":"Where do the dashboard KPIs come from, and what does the exception KPI signal?","options":[{"id":"a","text":"They are static placeholders that never change"},{"id":"b","text":"They reflect the latest run number, Planned order count, Firmed order count, and unresolved exception count — the exception chip turns red when there's something to act on, green when clear","isCorrect":true},{"id":"c","text":"They only show on simulation runs"},{"id":"d","text":"They count total customers and vendors"}],"explanation":"The dashboard KPIs summarize plan health: latest run, Planned orders, Firmed orders, and unresolved exceptions. The unresolved-exception chip is color-coded — red when greater than zero (action needed), green when zero."},{"id":"mr10","text":"A planned order's start date is earlier than its due date. Why?","options":[{"id":"a","text":"It is a data-entry error"},{"id":"b","text":"The start date is offset back from the due date by the part's lead time, so the order can be completed in time","isCorrect":true},{"id":"c","text":"Start date is always today regardless of due date"},{"id":"d","text":"Start and due dates are unrelated and chosen randomly"}],"explanation":"MRP time-phases each planned order: the due date is when the quantity is needed, and the start date is that due date minus the part's lead time, so production or procurement begins early enough to finish on time."},{"id":"mr11","text":"After you act on an exception (e.g., you expedited the supply order), what should you do in MRP?","options":[{"id":"a","text":"Delete the entire MRP run"},{"id":"b","text":"Click the resolve (check) action on the exception to mark it resolved and clear it from the unresolved list","isCorrect":true},{"id":"c","text":"Nothing — exceptions clear themselves immediately"},{"id":"d","text":"Re-run MRP as a simulation to remove it"}],"explanation":"Exceptions are a worklist. Once you've taken the suggested action, you mark the exception resolved (the check/done icon), which removes it from the unresolved count on the dashboard and the unresolved filter."},{"id":"mr12","text":"Which of these is NOT a source of demand or supply that MRP considers?","options":[{"id":"a","text":"Sales orders and dependent demand from BOMs (demand)"},{"id":"b","text":"On-hand inventory and open purchase orders (supply)"},{"id":"c","text":"Customer credit limits and payment terms","isCorrect":true},{"id":"d","text":"Master schedule entries and approved forecasts (demand)"}],"explanation":"MRP nets demand (sales orders, master schedule, forecasts, manual demand, dependent demand) against supply (on-hand, purchase orders, planned orders, production runs, in-transit). Customer credit limits and payment terms are accounting/sales concerns and play no part in material netting."},{"id":"mr13","text":"In Run History you click a run row. What does the Run Detail dialog let you do?","options":[{"id":"a","text":"Nothing — runs are not clickable"},{"id":"b","text":"See the parts the run touched, drill into a part's time-phased buckets (gross/scheduled/on-hand/net/releases), and read the pegging trail that traces each supply back to its demand","isCorrect":true},{"id":"c","text":"Permanently delete the run and all its planned orders"},{"id":"d","text":"Re-run the calculation with a different horizon in place"}],"explanation":"Clicking a run row opens Run Detail: a summary header, a 'parts touched' list, and — once you pick a part — its period-by-period netting buckets plus a pegging trail linking each demand to the supply MRP allocated. It's the read-only drill-down you use to verify a run or explain why a planned order exists."},{"id":"mr14","text":"On the Exceptions tab, why might a resolved exception not appear in the list?","options":[{"id":"a","text":"Resolved exceptions are deleted from the database"},{"id":"b","text":"The Exceptions tab opens filtered to 'Unresolved only' by default — switch the filter to 'All' to also see resolved ones","isCorrect":true},{"id":"c","text":"Resolved exceptions only appear on the dashboard, never on the tab"},{"id":"d","text":"You must re-run MRP to see resolved exceptions"}],"explanation":"The Exceptions tab defaults to the 'Unresolved only' filter (matching the dashboard's unresolved count). Resolved exceptions still exist — change the filter to 'All' to see them. The Planned Orders tab has a similar status filter (All/Planned/Firmed/Released/Cancelled)."}]}"""
        });

        Log.Information("Seeded MRP training modules");
    }
}
